const input = $input.first().json;
const body = input.body || input;
let content = body.content || '';
const googleDocUrl = body.googleDocUrl || '';
const pdfBase64 = body.pdfBase64 || '';
const pdfFileName = body.pdfFileName || 'document.pdf';
const courseTitle = body.courseTitle || 'Untitled Course';
const courseDescription = body.courseDescription || '';

const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY || 'YOUR_ANTHROPIC_KEY';
const SUPABASE_URL = 'https://lxgethcibldfcnmajutf.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY || 'YOUR_SUPABASE_SERVICE_KEY';

const systemPrompt = `You are an expert course designer for a premium LMS platform. Your job is to transform raw content into beautifully structured, pedagogically sound course material.

You MUST return ONLY valid JSON \u2014 no markdown fences, no explanation, no text outside the JSON.

JSON structure:
{
  "title": "course title",
  "description": "2-3 sentence course description",
  "modules": [
    {
      "title": "Module Title",
      "description": "Brief module description",
      "sections": [
        {
          "title": "Section Title",
          "blocks": [
            { "type": "block_type", "content": { ... } }
          ]
        }
      ]
    }
  ]
}

Available block types:

1. rich_text \u2014 For prose, explanations, instructions
   { "html": "<p>Content with <strong>bold</strong>, <em>italic</em></p>" }
   Use <h2> for section headings, <h3> for sub-headings, <p> for paragraphs,
   <ul>/<li> for bullets, <ol>/<li> for numbered lists.
   Keep paragraphs focused \u2014 break long text into multiple rich_text blocks.

2. callout \u2014 For highlighted information boxes
   { "calloutType": "tip|warning|formula|key-insight", "title": "Title", "body": "<p>HTML body</p>" }
   - tip: helpful advice, pro tips, best practices
   - warning: critical warnings, common mistakes, pitfalls
   - formula: rules, formulas, frameworks, principles
   - key-insight: key takeaways, important conclusions, aha moments

3. table \u2014 For structured/tabular data
   { "rows": [["Header1","Header2"],["Cell1","Cell2"]] }
   First row is always the header row.

4. workbook_prompt \u2014 For exercises, reflection questions, student input
   { "label": "Question or prompt text", "placeholder": "Guide text for what to write..." }
   Use these generously \u2014 they drive engagement and learning retention.

5. checklist \u2014 For action items, deliverable lists
   { "title": "Checklist Title", "description": "Optional description", "items": ["Item 1", "Item 2"] }

6. video \u2014 For video embeds
   { "url": "https://..." }

7. file \u2014 For downloadable resources
   { "label": "Description", "fileUrl": "", "fileName": "" }

Critical rules:
- NEVER summarize or skip content. Include EVERYTHING from the source.
- Transform flat content into a rich, engaging learning experience.
- Use callouts liberally for key insights, tips, warnings, and formulas.
- Add workbook_prompt blocks for exercises, reflection questions, and "apply this" moments.
- Break long text walls into digestible rich_text blocks with clear headings.
- Use tables whenever data can be presented in tabular format.
- Each distinct topic should be its own section.
- Sections should have 3-10 blocks each for good pacing.
- Module descriptions should explain what the learner will achieve.
- Make it feel like a premium, professionally designed course.
- Ensure the JSON is complete and valid.`;

try {
  // STEP 1: Resolve content from the appropriate source
  let claudeMessages;

  if (googleDocUrl.trim()) {
    // Google Doc mode
    const docIdMatch = googleDocUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
    if (!docIdMatch) {
      return [{ json: { success: false, error: 'Invalid Google Doc URL. Expected format: https://docs.google.com/document/d/DOC_ID/...' } }];
    }
    const docId = docIdMatch[1];
    const exportUrl = 'https://docs.google.com/document/d/' + docId + '/export?format=txt';

    const docRes = await fetch(exportUrl, { redirect: 'follow' });
    if (!docRes.ok) {
      return [{ json: { success: false, error: 'Failed to fetch Google Doc (HTTP ' + docRes.status + '). Make sure the document is shared with Anyone with the link.' } }];
    }
    content = await docRes.text();
    if (!content.trim()) {
      return [{ json: { success: false, error: 'Google Doc appears to be empty.' } }];
    }

    claudeMessages = [{
      role: 'user',
      content: 'Parse this course content into structured LMS JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription + '\n' : '') + '\nContent:\n\n' + content
    }];

  } else if (pdfBase64.trim()) {
    // PDF mode \u2014 send the PDF directly to Claude as a document
    claudeMessages = [{
      role: 'user',
      content: [
        {
          type: 'document',
          source: {
            type: 'base64',
            media_type: 'application/pdf',
            data: pdfBase64
          }
        },
        {
          type: 'text',
          text: 'Parse this PDF document into structured LMS course JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription : '') + '\n\nExtract ALL content from the PDF and structure it into modules, sections, and content blocks. Do not skip or summarize anything.'
        }
      ]
    }];

  } else if (content.trim()) {
    // Paste mode
    claudeMessages = [{
      role: 'user',
      content: 'Parse this course content into structured LMS JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription + '\n' : '') + '\nContent:\n\n' + content
    }];

  } else {
    return [{ json: { success: false, error: 'No content provided. Paste text, provide a Google Doc URL, or upload a PDF.' } }];
  }

  // STEP 2: Call Claude Opus
  const claudeRes = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    body: JSON.stringify({
      model: 'claude-opus-4-20250514',
      max_tokens: 32000,
      system: systemPrompt,
      messages: claudeMessages,
    }),
  });

  const claudeData = await claudeRes.json();

  if (claudeData.error) {
    return [{ json: { success: false, error: 'Claude API error: ' + claudeData.error.message } }];
  }

  // STEP 3: Parse the structured response
  let responseText = claudeData.content[0].text;
  responseText = responseText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch (e) {
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        parsed = JSON.parse(jsonMatch[0]);
      } catch (e2) {
        return [{ json: { success: false, error: 'Failed to parse Claude response as JSON', raw: responseText.substring(0, 1000) } }];
      }
    } else {
      return [{ json: { success: false, error: 'No JSON found in Claude response', raw: responseText.substring(0, 1000) } }];
    }
  }

  // STEP 4: Insert everything into Supabase
  async function dbInsert(table, data) {
    const res = await fetch(SUPABASE_URL + '/rest/v1/' + table, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
      body: JSON.stringify(data),
    });
    const result = await res.json();
    return Array.isArray(result) ? result[0] : result;
  }

  const course = await dbInsert('courses', {
    title: parsed.title || courseTitle,
    description: parsed.description || courseDescription || null,
    status: 'draft',
    sort_order: 0,
  });

  if (!course || !course.id) {
    return [{ json: { success: false, error: 'Failed to create course in database', detail: JSON.stringify(course) } }];
  }

  let totalModules = 0;
  let totalSections = 0;
  let totalBlocks = 0;

  for (let mi = 0; mi < (parsed.modules || []).length; mi++) {
    const mod = parsed.modules[mi];
    const module = await dbInsert('modules', {
      course_id: course.id,
      title: mod.title,
      description: mod.description || null,
      sort_order: mi,
    });
    totalModules++;

    if (!module || !module.id) continue;

    for (let si = 0; si < (mod.sections || []).length; si++) {
      const sec = mod.sections[si];
      const section = await dbInsert('sections', {
        module_id: module.id,
        title: sec.title,
        sort_order: si,
      });
      totalSections++;

      if (!section || !section.id) continue;

      const blocks = (sec.blocks || []).map((b, bi) => ({
        section_id: section.id,
        type: b.type,
        content: b.content,
        sort_order: bi,
      }));

      if (blocks.length > 0) {
        const batchRes = await fetch(SUPABASE_URL + '/rest/v1/content_blocks', {
          method: 'POST',
          headers: {
            'apikey': SUPABASE_KEY,
            'Authorization': 'Bearer ' + SUPABASE_KEY,
            'Content-Type': 'application/json',
            'Prefer': 'return=representation',
          },
          body: JSON.stringify(blocks),
        });
        const inserted = await batchRes.json();
        totalBlocks += Array.isArray(inserted) ? inserted.length : 1;
      }
    }
  }

  return [{
    json: {
      success: true,
      courseId: course.id,
      courseTitle: course.title,
      modulesCreated: totalModules,
      sectionsCreated: totalSections,
      blocksCreated: totalBlocks,
      message: 'Course "' + course.title + '" imported with ' + totalModules + ' modules, ' + totalSections + ' sections, and ' + totalBlocks + ' content blocks.',
    }
  }];
} catch (err) {
  return [{ json: { success: false, error: err.message || 'Unknown error during import' } }];
}
